// Worked focus: cmem-lifetime-begin-end — Identify precisely when each object lifetime begins and ends, including allocated storage and subobjects.
/* Evidence: cmem-worked-cmem-objects-storage-lifetime-2 */
/* Browser practice: PicoC 3.2.2 C89/C90 plus selected C99. */
/* Changed case 8138; native C23 claims require explicit transfer gates. */
#include <stdio.h>
#include <stdlib.h>
#include <string.h>


struct lifetime_handle { int value; unsigned generation; int live; };

static int worked_cmem_objects_storage_lifetime_2(const struct lifetime_handle *item, unsigned expected) {
  if (item == NULL || !item->live) return -1;
  if (item->generation != expected) return -2;
  return item->value;
}

int main(void) {
  struct lifetime_handle item = { 12, 4u, 1 };
  int stale = worked_cmem_objects_storage_lifetime_2(&item, 5u);
  int live = worked_cmem_objects_storage_lifetime_2(&item, 4u);
  int invariant = stale == -2 && live == 12;
  printf("lifetime stale=%d live=%d invariant=%d\n", stale, live, invariant);
  return invariant ? 0 : 1;
}

